#ifndef SRC_LIB_WIFI_CONFIG_PORTAL_PAGE_GENERATED_H
#define SRC_LIB_WIFI_CONFIG_PORTAL_PAGE_GENERATED_H

static const char kWifiConfigPortalHtmlTemplate[] = "<!doctype html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>{{TITLE}}</title>\n  <style>\n    :root{color-scheme:light;--bg:#eef2f5;--panel:#fff;--ink:#17202a;--muted:#5d6875;--line:#d8e0e8;--accent:#0f766e;--accent-2:#2457a6;--danger:#b42318;}\n    *{box-sizing:border-box;}\n    body{margin:0;background:var(--bg);color:var(--ink);font-family:Arial,Helvetica,sans-serif;font-size:15px;}\n    .shell{max-width:1040px;margin:0 auto;padding:20px;}\n    .topbar{display:flex;align-items:flex-start;justify-content:space-between;gap:16px;margin-bottom:14px;}\n    h1{margin:0;font-size:26px;line-height:1.18;letter-spacing:0;}\n    .sub{margin:6px 0 0;color:var(--muted);font-size:14px;}\n    .status{display:grid;grid-template-columns:repeat(2,minmax(150px,1fr));gap:8px;min-width:320px;}\n    .status div{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:10px 12px;}\n    .status span{display:block;color:var(--muted);font-size:12px;margin-bottom:3px;}\n    .mono{font-family:Consolas,monospace;}\n    .nav{display:flex;gap:8px;margin:0 0 14px;border-bottom:1px solid var(--line);}\n    .nav a{display:inline-block;padding:10px 12px;text-decoration:none;color:var(--muted);border-bottom:3px solid transparent;font-weight:700;}\n    .nav a.active{color:var(--accent);border-bottom-color:var(--accent);}\n    .panel{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:18px;margin-bottom:14px;}\n    .section-head{display:flex;align-items:center;justify-content:space-between;gap:12px;margin-bottom:12px;}\n    h2{margin:0;font-size:17px;letter-spacing:0;}\n    .hint{color:var(--muted);font-size:13px;}\n    .grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px 16px;}\n    label{display:block;margin:0 0 6px;font-weight:700;font-size:13px;}\n    input,select{width:100%;min-height:40px;padding:9px 10px;border:1px solid #c5ced8;border-radius:6px;font-size:15px;background:#fff;color:var(--ink);}\n    input[type=checkbox]{width:auto;min-height:0;margin-right:8px;}\n    .row{display:flex;gap:10px;align-items:center;flex-wrap:wrap;}\n    .row select{flex:1;min-width:220px;width:auto;}\n    .span-2{grid-column:1/-1;}\n    .actions{display:flex;gap:10px;align-items:center;justify-content:flex-end;flex-wrap:wrap;margin-top:16px;}\n    button,.button{display:inline-flex;align-items:center;justify-content:center;min-height:40px;padding:10px 14px;border:0;border-radius:6px;background:var(--accent);color:#fff;font-size:14px;font-weight:700;text-decoration:none;cursor:pointer;}\n    .button.secondary,button.secondary{background:#e8edf3;color:#17202a;border:1px solid var(--line);}\n    .btn-small{min-height:36px;padding:8px 11px;}\n    .notice{border-left:4px solid var(--accent-2);padding:10px 12px;background:#edf4ff;color:#25364c;border-radius:4px;margin:0 0 14px;}\n    .footer-links{display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-top:10px;}\n    .footer-links a{color:var(--accent-2);font-weight:700;text-decoration:none;}\n    @media(max-width:760px){\n      .shell{padding:14px;}\n      .topbar{display:block;}\n      .status{grid-template-columns:1fr;min-width:0;margin-top:12px;}\n      .grid{grid-template-columns:1fr;}\n      .span-2{grid-column:auto;}\n      .actions{justify-content:stretch;}\n      button,.button{width:100%;}\n    }\n  </style>\n</head>\n<body>\n  <main class=\"shell\">\n    <div class=\"topbar\">\n      <div>\n        <h1>{{HEADLINE}}</h1>\n        <p class=\"sub\">{{INTRO}}</p>\n      </div>\n      <div class=\"status\">\n        <div><span>Config AP</span><strong class=\"mono\">{{AP_IP}}</strong></div>\n        <div><span>Station IP</span><strong class=\"mono\">{{STA_IP}}</strong></div>\n      </div>\n    </div>\n\n    <nav class=\"nav\">\n      <a class=\"active\" href=\"/\">Settings</a>\n      <a href=\"/update\">Firmware</a>\n    </nav>\n\n    <p class=\"notice\">Hold the BOOT button for 5 seconds after startup to reset WiFi and server settings.</p>\n    <p class=\"sub\">Firmware version <span class=\"mono\">{{VERSION}}</span></p>\n\n    <form method=\"post\" action=\"/save\">\n      <section class=\"panel\">\n        <div class=\"section-head\">\n          <h2>Network</h2>\n          <span class=\"hint\" id=\"scan-status\">Scan runs on demand to keep hotspot startup stable.</span>\n        </div>\n        <div class=\"grid\">\n          <div>\n            <label>WiFi SSID</label>\n            <input id=\"wifi-ssid-input\" name=\"wifi_ssid\" value=\"{{WIFI_SSID}}\" autocomplete=\"off\">\n          </div>\n          <div>\n            <label>WiFi Password</label>\n            <input name=\"wifi_password\" value=\"{{WIFI_PASSWORD}}\">\n          </div>\n          <div class=\"span-2\">\n            <label>Nearby WiFi</label>\n            <div class=\"row\">\n              <select id=\"wifi-ssid-select\" onchange=\"applySelectedWifi()\">\n                <option value=\"\">Select detected WiFi...</option>\n                {{SSID_OPTIONS}}\n              </select>\n              <button class=\"secondary btn-small\" type=\"button\" onclick=\"scanWifi()\">Scan</button>\n            </div>\n          </div>\n          <div>\n            <label>Server Host / IP</label>\n            <input name=\"server_host\" value=\"{{SERVER_HOST}}\">\n          </div>\n          <div>\n            <label>Server Port</label>\n            <input name=\"server_port\" value=\"{{SERVER_PORT}}\">\n          </div>\n        </div>\n      </section>\n\n      <section class=\"panel\">\n        <div class=\"section-head\">\n          <h2>Radio</h2>\n        </div>\n        <div class=\"grid\">\n          <div>\n            <label>Channel (0-7)</label>\n            <input name=\"channel\" value=\"{{CHANNEL}}\">\n          </div>\n          <div>\n            <label>Callsign</label>\n            <input name=\"callsign\" value=\"{{CALLSIGN}}\">\n          </div>\n          <div>\n            <label>Callsign SSID</label>\n            <input name=\"callsign_ssid\" value=\"{{CALLSIGN_SSID}}\">\n          </div>\n          <div>\n            <label>ES8311 HP Drive</label>\n            <label class=\"hint\"><input type=\"checkbox\" name=\"hp_drive_enabled\" value=\"1\" {{HP_DRIVE_CHECKED}}>Enable headphone output drive (REG13 HPSW)</label>\n          </div>\n        </div>\n      </section>\n\n      <section class=\"panel\">\n        <div class=\"section-head\">\n          <h2>Audio</h2>\n        </div>\n        <div class=\"grid\">\n          <div>\n            <label>Mic Volume (0-255)</label>\n            <input name=\"mic_volume\" value=\"{{MIC_VOLUME}}\">\n          </div>\n          <div>\n            <label>Line Out Volume (0-255)</label>\n            <input name=\"line_out_volume\" value=\"{{LINE_OUT_VOLUME}}\">\n          </div>\n        </div>\n        <div class=\"actions\">\n          <a class=\"button secondary\" href=\"/update\">Firmware update</a>\n          <button type=\"submit\">{{SUBMIT_LABEL}}</button>\n        </div>\n      </section>\n    </form>\n    <div class=\"footer-links\">{{FOOTER}}</div>\n  </main>\n  <script>\n    function applySelectedWifi() {\n      const select = document.getElementById('wifi-ssid-select');\n      const input = document.getElementById('wifi-ssid-input');\n      if (select.value) {\n        input.value = select.value;\n      }\n    }\n\n    async function scanWifi() {\n      const status = document.getElementById('scan-status');\n      const list = document.getElementById('wifi-ssid-select');\n      status.textContent = 'Scanning...';\n      try {\n        const res = await fetch('/scan', {cache: 'no-store'});\n        if (!res.ok) throw new Error('scan failed');\n        const items = await res.json();\n        list.innerHTML = '<option value=\"\">Select detected WiFi...</option>';\n        items.forEach((item) => {\n          const opt = document.createElement('option');\n          opt.value = item.ssid;\n          opt.textContent = item.label;\n          list.appendChild(opt);\n        });\n        status.textContent = items.length ? ('Found ' + items.length + ' WiFi networks') : 'No WiFi networks found';\n      } catch (e) {\n        status.textContent = 'Scan failed';\n      }\n    }\n  </script>\n</body>\n</html>\n";

#endif
